object AWSServiceExample extends App {
  val credentialsManager = new AWSCredentialsManager(
    StaticCredentials("your-access-key-id", "your-secret-access-key")
  )
  
  val region = Region.US_EAST_1
  val serviceManager = new AWSServiceManager(credentialsManager, region)
  
  serviceManager.s3Service.listBuckets() match {
    case Success(buckets) =>
      println(s"Found ${buckets.size} buckets")
      buckets.foreach(bucket => println(s"  - ${bucket.name()}"))
    case Failure(exception) =>
      println(s"Failed to list buckets: ${exception.getMessage}")
  }
  
  val tableName = "test-table"
  serviceManager.dynamoDbService.createTable(tableName, "id", ScalarAttributeType.S) match {
    case Success(response) =>
      println(s"Created table: ${response.tableDescription().tableName()}")
    case Failure(exception) =>
      println(s"Failed to create table: ${exception.getMessage}")
  }
  
  val item = Map(
    "id" -> AttributeValue.builder().s("123").build(),
    "name" -> AttributeValue.builder().s("John Doe").build()
  )
  serviceManager.dynamoDbService.putItem(tableName, item)
  
  val queueName = "test-queue"
  serviceManager.sqsService.createQueue(queueName) match {
    case Success(queueUrl) =>
      println(s"Created queue: $queueUrl")
      serviceManager.sqsService.sendMessage(queueUrl, "Hello, SQS!")
    case Failure(exception) =>
      println(s"Failed to create queue: ${exception.getMessage}")
  }
  
  serviceManager.closeAll()
}